// shared/internal-auth.js
// Shared module for internal service authentication
// ============================================

export class InternalAuth {
  constructor(signingSecret) {
    this.signingSecret = signingSecret;
    this.maxTimestampDrift = 300000; // 5 minutes
  }

  async verifyInternalRequest(request) {
    const signature = request.headers.get('X-Internal-Signature');
    const timestamp = request.headers.get('X-Internal-Timestamp');
    const gatewaySource = request.headers.get('X-Gateway-Source');

    if (!signature || !timestamp || gatewaySource !== 'edge-gateway') {
      return { valid: false, error: 'Missing internal authentication headers' };
    }

    // Check timestamp to prevent replay attacks
    const requestTime = parseInt(timestamp);
    const now = Date.now();
    if (isNaN(requestTime) || Math.abs(now - requestTime) > this.maxTimestampDrift) {
      return { valid: false, error: 'Request timestamp out of range' };
    }

    // Verify HMAC signature
    const url = new URL(request.url);
    const body = request.method !== 'GET' && request.method !== 'HEAD'
      ? await request.clone().text()
      : '';

    const signaturePayload = `${timestamp}:${url.pathname}${url.search}:${body}`;

    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(this.signingSecret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['verify']
    );

    const signatureBytes = Uint8Array.from(atob(signature), c => c.charCodeAt(0));
    const valid = await crypto.subtle.verify(
      'HMAC',
      key,
      signatureBytes,
      encoder.encode(signaturePayload)
    );

    if (!valid) {
      return { valid: false, error: 'Invalid signature' };
    }

    return {
      valid: true,
      context: {
        requestId: request.headers.get('X-Request-ID'),
        userId: request.headers.get('X-User-ID'),
        userRole: request.headers.get('X-User-Role'),
        forwardedFor: request.headers.get('X-Forwarded-For'),
      },
    };
  }
}


