import { InternalAuth } from './internal-auth.js';

export class BaseServiceWorker {
  constructor(serviceName) {
    this.serviceName = serviceName;
    this.routes = new Map();
  }

  // Register route handlers
  get(path, handler) {
    this.routes.set(`GET:${path}`, handler);
  }

  post(path, handler) {
    this.routes.set(`POST:${path}`, handler);
  }

  put(path, handler) {
    this.routes.set(`PUT:${path}`, handler);
  }

  delete(path, handler) {
    this.routes.set(`DELETE:${path}`, handler);
  }

  patch(path, handler) {
    this.routes.set(`PATCH:${path}`, handler);
  }

  // Match route with path parameters
  matchRoute(method, pathname) {
    // Exact match
    const exactKey = `${method}:${pathname}`;
    if (this.routes.has(exactKey)) {
      return { handler: this.routes.get(exactKey), params: {} };
    }

    // Pattern match with path parameters
    for (const [routeKey, handler] of this.routes) {
      const [routeMethod, routePath] = routeKey.split(':');
      if (routeMethod !== method) continue;

      const routeParts = routePath.split('/').filter(Boolean);
      const pathParts = pathname.split('/').filter(Boolean);

      if (routeParts.length !== pathParts.length) continue;

      const params = {};
      let match = true;

      for (let i = 0; i < routeParts.length; i++) {
        if (routeParts[i].startsWith(':')) {
          params[routeParts[i].slice(1)] = decodeURIComponent(pathParts[i]);
        } else if (routeParts[i] !== pathParts[i]) {
          match = false;
          break;
        }
      }

      if (match) {
        return { handler, params };
      }
    }

    return null;
  }

  // Create the fetch handler
  createFetchHandler() {
    return async (request, env, ctx) => {
      const startTime = Date.now();
      const requestId = request.headers.get('X-Request-ID') || 'unknown';

      try {
        // Verify internal authentication
        const auth = new InternalAuth(env.INTERNAL_SIGNING_SECRET);
        const verification = await auth.verifyInternalRequest(request);

        if (!verification.valid) {
          console.error(`[${this.serviceName}] Auth failed: ${verification.error}, requestId: ${requestId}`);
          return new Response(JSON.stringify({
            error: 'Unauthorized internal request',
            service: this.serviceName,
          }), {
            status: 403,
            headers: { 'Content-Type': 'application/json' },
          });
        }

        const url = new URL(request.url);
        const routeMatch = this.matchRoute(request.method, url.pathname);

        if (!routeMatch) {
          return new Response(JSON.stringify({
            error: 'Route not found',
            service: this.serviceName,
          }), {
            status: 404,
            headers: { 'Content-Type': 'application/json' },
          });
        }

        // Build context object
        const serviceContext = {
          requestId,
          userId: verification.context.userId,
          userRole: verification.context.userRole,
          params: routeMatch.params,
          query: Object.fromEntries(url.searchParams),
          env,
          ctx,
          // Helper to call other services via bindings
          callService: async (serviceName, path, options = {}) => {
            return this.callInternalService(env, serviceName, path, options, verification.context);
          },
        };

        // Parse body if present
        if (request.method !== 'GET' && request.method !== 'HEAD') {
          const contentType = request.headers.get('content-type');
          if (contentType?.includes('application/json')) {
            try {
              serviceContext.body = await request.json();
            } catch {
              return new Response(JSON.stringify({
                error: 'Invalid JSON body',
                service: this.serviceName,
              }), {
                status: 400,
                headers: { 'Content-Type': 'application/json' },
              });
            }
          } else {
            serviceContext.body = await request.text();
          }
        }

        // Execute handler
        const result = await routeMatch.handler(serviceContext);

        // Format response
        const responseBody = typeof result.body === 'string' ? result.body : JSON.stringify(result.body);
        const responseHeaders = new Headers(result.headers || {});
        responseHeaders.set('Content-Type', 'application/json');
        responseHeaders.set('X-Service', this.serviceName);
        responseHeaders.set('X-Service-Time', `${Date.now() - startTime}ms`);

        return new Response(responseBody, {
          status: result.status || 200,
          headers: responseHeaders,
        });

      } catch (err) {
        console.error(`[${this.serviceName}] Error:`, err.message, err.stack);
        return new Response(JSON.stringify({
          error: 'Internal service error',
          service: this.serviceName,
          requestId,
        }), {
          status: 500,
          headers: { 'Content-Type': 'application/json' },
        });
      }
    };
  }

  // Call another internal service via service binding
  async callInternalService(env, serviceName, path, options = {}, parentContext = {}) {
    const service = env[serviceName];
    if (!service) {
      throw new Error(`Service binding ${serviceName} not available`);
    }

    const timestamp = Date.now().toString();
    const body = options.body ? JSON.stringify(options.body) : '';
    const signaturePayload = `${timestamp}:${path}:${body}`;

    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(env.INTERNAL_SIGNING_SECRET),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['sign']
    );
    const signatureBuffer = await crypto.subtle.sign('HMAC', key, encoder.encode(signaturePayload));
    const signature = btoa(String.fromCharCode(...new Uint8Array(signatureBuffer)));

    const headers = new Headers({
      'Content-Type': 'application/json',
      'X-Request-ID': parentContext.requestId || generateRequestId(),
      'X-User-ID': parentContext.userId || '',
      'X-User-Role': parentContext.userRole || '',
      'X-Internal-Signature': signature,
      'X-Internal-Timestamp': timestamp,
      'X-Gateway-Source': 'edge-gateway',
      'X-Calling-Service': this.serviceName,
    });

    const internalRequest = new Request(`https://internal-service${path}`, {
      method: options.method || 'GET',
      headers,
      body: body || undefined,
    });

    const response = await service.fetch(internalRequest);
    return response.json();
  }
}

function generateRequestId() {
  const array = new Uint8Array(16);
  crypto.getRandomValues(array);
  return Array.from(array, b => b.toString(16).padStart(2, '0')).join('');
}


