// ============================================
// worker-order-service/src/index.js
// Internal Order Service Worker
// ============================================

import { BaseServiceWorker } from '../../shared/base-service.js';

const service = new BaseServiceWorker('order-service');

// GET /orders
service.get('/orders', async (ctx) => {
  const { userId, userRole } = ctx;
  const { status: filterStatus, page = '1', limit = '20' } = ctx.query;

  const pageNum = Math.max(1, parseInt(page) || 1);
  const limitNum = Math.min(100, Math.max(1, parseInt(limit) || 20));

  // Simulated orders
  const orders = [
    { id: 'ord-001', userId: '1', productId: 'prod-001', status: 'completed', total: 29.99 },
    { id: 'ord-002', userId: '1', productId: 'prod-002', status: 'pending', total: 49.99 },
    { id: 'ord-003', userId: '2', productId: 'prod-001', status: 'shipped', total: 29.99 },
  ];

  let filtered = orders;

  // Non-admin users can only see their own orders
  if (userRole !== 'admin') {
    filtered = filtered.filter(o => o.userId === userId);
  }

  if (filterStatus) {
    filtered = filtered.filter(o => o.status === filterStatus);
  }

  return {
    status: 200,
    body: {
      orders: filtered.slice((pageNum - 1) * limitNum, pageNum * limitNum),
      pagination: {
        page: pageNum,
        limit: limitNum,
        total: filtered.length,
      },
      requestId: ctx.requestId,
    },
  };
});

// GET /orders/:id
service.get('/orders/:id', async (ctx) => {
  const { id } = ctx.params;

  if (!/^[a-zA-Z0-9-]+$/.test(id)) {
    return { status: 400, body: { error: 'Invalid order ID format' } };
  }

  const order = {
    id,
    userId: '1',
    items: [
      { productId: 'prod-001', quantity: 2, price: 14.99 },
    ],
    status: 'completed',
    total: 29.98,
    createdAt: '2024-01-15T10:30:00Z',
  };

  // Authorization check
  if (ctx.userRole !== 'admin' && order.userId !== ctx.userId) {
    return { status: 403, body: { error: 'Access denied' } };
  }

  // Enrich with product details from product service
  try {
    const enrichedItems = await Promise.all(
      order.items.map(async (item) => {
        try {
          const product = await ctx.callService('PRODUCT_SERVICE', `/products/${item.productId}`);
          return { ...item, productName: product.product?.name || 'Unknown' };
        } catch {
          return { ...item, productName: 'Unknown' };
        }
      })
    );
    order.items = enrichedItems;
  } catch (err) {
    console.error('Failed to enrich order items:', err.message);
  }

  return {
    status: 200,
    body: { order, requestId: ctx.requestId },
  };
});

// POST /orders
service.post('/orders', async (ctx) => {
  const { body } = ctx;

  // Validate order
  if (!body.items || !Array.isArray(body.items) || body.items.length === 0) {
    return { status: 400, body: { error: 'Order must contain at least one item' } };
  }

  if (body.items.length > 50) {
    return { status: 400, body: { error: 'Order cannot contain more than 50 items' } };
  }

  for (const item of body.items) {
    if (!item.productId || typeof item.productId !== 'string') {
      return { status: 400, body: { error: 'Each item must have a valid productId' } };
    }
    if (!item.quantity || typeof item.quantity !== 'number' || item.quantity < 1 || item.quantity > 999) {
      return { status: 400, body: { error: 'Each item must have a valid quantity (1-999)' } };
    }
  }

  // Verify products exist and get prices
  let total = 0;
  const verifiedItems = [];

  for (const item of body.items) {
    try {
      const productData = await ctx.callService('PRODUCT_SERVICE', `/products/${item.productId}`);
      if (!productData.product) {
        return { status: 400, body: { error: `Product ${item.productId} not found` } };
      }
      const itemTotal = productData.product.price * item.quantity;
      total += itemTotal;
      verifiedItems.push({
        productId: item.productId,
        productName: productData.product.name,
        quantity: item.quantity,
        price: productData.product.price,
        itemTotal,
      });
    } catch (err) {
      return { status: 502, body: { error: `Failed to verify product ${item.productId}` } };
    }
  }

  const idBytes = new Uint8Array(8);
  crypto.getRandomValues(idBytes);
  const orderId = 'ord-' + Array.from(idBytes, b => b.toString(16).padStart(2, '0')).join('');

  const newOrder = {
    id: orderId,
    userId: ctx.userId,
    items: verifiedItems,
    status: 'pending',
    total: Math.round(total * 100) / 100,
    createdAt: new Date().toISOString(),
  };

  // Send notification
  ctx.ctx.waitUntil(
    ctx.callService('NOTIFICATION_SERVICE', '/notifications/send', {
      method: 'POST',
      body: {
        type: 'order_created',
        userId: ctx.userId,
        orderId: newOrder.id,
        total: newOrder.total,
      },
    }).catch(err => console.error('Order notification failed:', err.message))
  );

  return {
    status: 201,
    body: { order: newOrder, requestId: ctx.requestId },
  };
});

// PATCH /orders/:id/status
service.patch('/orders/:id/status', async (ctx) => {
  const { id } = ctx.params;
  const { body } = ctx;

  if (ctx.userRole !== 'admin') {
    return { status: 403, body: { error: 'Admin access required' } };
  }

  const validStatuses = ['pending', 'confirmed', 'processing', 'shipped', 'delivered', 'cancelled'];
  if (!body.status || !validStatuses.includes(body.status)) {
    return { status: 400, body: { error: `Invalid status. Must be one of: ${validStatuses.join(', ')}` } };
  }

  const updatedOrder = {
    id,
    status: body.status,
    updatedAt: new Date().toISOString(),
  };

  // Notify user of status change
  ctx.ctx.waitUntil(
    ctx.callService('NOTIFICATION_SERVICE', '/notifications/send', {
      method: 'POST',
      body: {
        type: 'order_status_changed',
        orderId: id,
        newStatus: body.status,
      },
    }).catch(err => console.error('Status notification failed:', err.message))
  );

  return {
    status: 200,
    body: { order: updatedOrder, requestId: ctx.requestId },
  };
});

export default {
  fetch: service.createFetchHandler(),
};


