// ============================================
// worker-product-service/src/index.js
// Internal Product Service Worker
// ============================================

import { BaseServiceWorker } from '../../shared/base-service.js';

const service = new BaseServiceWorker('product-service');

// Simulated product catalog
const PRODUCTS = new Map([
  ['prod-001', { id: 'prod-001', name: 'Edge Computing Guide', price: 14.99, category: 'books', stock: 100 }],
  ['prod-002', { id: 'prod-002', name: 'Cloudflare Workers T-Shirt', price: 24.99, category: 'apparel', stock: 50 }],
  ['prod-003', { id: 'prod-003', name: 'Serverless Architecture Poster', price: 9.99, category: 'decor', stock: 200 }],
  ['prod-004', { id: 'prod-004', name: 'WebAssembly Sticker Pack', price: 4.99, category: 'accessories', stock: 500 }],
]);

// GET /products
service.get('/products', async (ctx) => {
  const { category, minPrice, maxPrice, search, page = '1', limit = '20' } = ctx.query;

  let products = Array.from(PRODUCTS.values());

  if (category) {
    products = products.filter(p => p.category === category);
  }

  if (minPrice) {
    const min = parseFloat(minPrice);
    if (!isNaN(min)) {
      products = products.filter(p => p.price >= min);
    }
  }

  if (maxPrice) {
    const max = parseFloat(maxPrice);
    if (!isNaN(max)) {
      products = products.filter(p => p.price <= max);
    }
  }

  if (search) {
    const searchLower = search.toLowerCase();
    products = products.filter(p =>
      p.name.toLowerCase().includes(searchLower) ||
      p.category.toLowerCase().includes(searchLower)
    );
  }

  const pageNum = Math.max(1, parseInt(page) || 1);
  const limitNum = Math.min(100, Math.max(1, parseInt(limit) || 20));
  const start = (pageNum - 1) * limitNum;

  return {
    status: 200,
    body: {
      products: products.slice(start, start + limitNum),
      pagination: {
        page: pageNum,
        limit: limitNum,
        total: products.length,
      },
      requestId: ctx.requestId,
    },
  };
});

// GET /products/:id
service.get('/products/:id', async (ctx) => {
  const { id } = ctx.params;

  if (!/^[a-zA-Z0-9-]+$/.test(id)) {
    return { status: 400, body: { error: 'Invalid product ID format' } };
  }

  const product = PRODUCTS.get(id);
  if (!product) {
    return { status: 404, body: { error: 'Product not found' } };
  }

  return {
    status: 200,
    body: { product, requestId: ctx.requestId },
    headers: {
      'Cache-Control': 'public, max-age=300', // Cache product data for 5 minutes
    },
  };
});

// POST /products (admin only)
service.post('/products', async (ctx) => {
  if (ctx.userRole !== 'admin') {
    return { status: 403, body: { error: 'Admin access required' } };
  }

  const { body } = ctx;

  if (!body.name || typeof body.name !== 'string' || body.name.length < 1 || body.name.length > 200) {
    return { status: 400, body: { error: 'Invalid product name' } };
  }

  if (typeof body.price !== 'number' || body.price < 0 || body.price > 99999.99) {
    return { status: 400, body: { error: 'Invalid price' } };
  }

  if (!body.category || typeof body.category !== 'string') {
    return { status: 400, body: { error: 'Invalid category' } };
  }

  const idBytes = new Uint8Array(4);
  crypto.getRandomValues(idBytes);
  const productId = 'prod-' + Array.from(idBytes, b => b.toString(16).padStart(2, '0')).join('');

  const newProduct = {
    id: productId,
    name: body.name.trim(),
    price: Math.round(body.price * 100) / 100,
    category: body.category.trim().toLowerCase(),
    stock: body.stock || 0,
    createdAt: new Date().toISOString(),
  };

  PRODUCTS.set(productId, newProduct);

  return {
    status: 201,
    body: { product: newProduct, requestId: ctx.requestId },
  };
});

// PUT /products/:id (admin only)
service.put('/products/:id', async (ctx) => {
  if (ctx.userRole !== 'admin') {
    return { status: 403, body: { error: 'Admin access required' } };
  }

  const { id } = ctx.params;
  const existing = PRODUCTS.get(id);

  if (!existing) {
    return { status: 404, body: { error: 'Product not found' } };
  }

  const { body } = ctx;
  const updated = {
    ...existing,
    name: body.name?.trim() || existing.name,
    price: typeof body.price === 'number' ? Math.round(body.price * 100) / 100 : existing.price,
    category: body.category?.trim().toLowerCase() || existing.category,
    stock: typeof body.stock === 'number' ? body.stock : existing.stock,
    updatedAt: new Date().toISOString(),
  };

  PRODUCTS.set(id, updated);

  return {
    status: 200,
    body: { product: updated, requestId: ctx.requestId },
  };
});

// DELETE /products/:id (admin only)
service.delete('/products/:id', async (ctx) => {
  if (ctx.userRole !== 'admin') {
    return { status: 403, body: { error: 'Admin access required' } };
  }

  const { id } = ctx.params;
  if (!PRODUCTS.has(id)) {
    return { status: 404, body: { error: 'Product not found' } };
  }

  PRODUCTS.delete(id);

  return {
    status: 200,
    body: { deleted: true, productId: id, requestId: ctx.requestId },
  };
});

export default {
  fetch: service.createFetchHandler(),
};


