// ============================================
// worker-notification-service/src/index.js
// Internal Notification Service Worker
// ============================================

import { BaseServiceWorker } from '../../shared/base-service.js';

const service = new BaseServiceWorker('notification-service');

// Notification templates
const TEMPLATES = {
  user_created: (data) => ({
    subject: 'Welcome!',
    message: `Welcome to our platform! Your account has been created.`,
    channel: 'email',
  }),
  order_created: (data) => ({
    subject: 'Order Confirmation',
    message: `Your order ${data.orderId} has been placed. Total: $${data.total}`,
    channel: 'email',
  }),
  order_status_changed: (data) => ({
    subject: 'Order Update',
    message: `Your order ${data.orderId} status has been updated to: ${data.newStatus}`,
    channel: 'email',
  }),
};

// POST /notifications/send
service.post('/notifications/send', async (ctx) => {
  const { body } = ctx;

  if (!body.type || typeof body.type !== 'string') {
    return { status: 400, body: { error: 'Notification type is required' } };
  }

  const template = TEMPLATES[body.type];
  if (!template) {
    return { status: 400, body: { error: `Unknown notification type: ${body.type}` } };
  }

  const notification = template(body);

  // Generate notification ID
  const idBytes = new Uint8Array(8);
  crypto.getRandomValues(idBytes);
  const notificationId = 'notif-' + Array.from(idBytes, b => b.toString(16).padStart(2, '0')).join('');

  const record = {
    id: notificationId,
    type: body.type,
    userId: body.userId || ctx.userId,
    channel: notification.channel,
    subject: notification.subject,
    message: notification.message,
    status: 'queued',
    createdAt: new Date().toISOString(),
  };

  // In production: store in KV/D1 and trigger actual email/push via external API
  console.log(`[notification-service] Sending notification:`, JSON.stringify(record));

  // If we need user details for the notification
  if (body.userId && ctx.env.USER_SERVICE) {
    try {
      const userData = await ctx.callService('USER_SERVICE', `/users/${body.userId}`);
      record.recipientEmail = userData.user?.email;
    } catch (err) {
      console.error('Failed to fetch user for notification:', err.message);
    }
  }

  return {
    status: 202,
    body: {
      notification: record,
      requestId: ctx.requestId,
    },
  };
});

// GET /notifications
service.get('/notifications', async (ctx) => {
  // Return recent notifications for the authenticated user
  const notifications = [
    {
      id: 'notif-001',
      type: 'order_created',
      subject: 'Order Confirmation',
      message: 'Your order ord-001 has been placed.',
      status: 'delivered',
      createdAt: '2024-01-15T10:30:00Z',
    },
  ];

  return {
    status: 200,
    body: { notifications, requestId: ctx.requestId },
  };
});

// GET /notifications/:id
service.get('/notifications/:id', async (ctx) => {
  const { id } = ctx.params;

  if (!/^[a-zA-Z0-9-]+$/.test(id)) {
    return { status: 400, body: { error: 'Invalid notification ID format' } };
  }

  const notification = {
    id,
    type: 'order_created',
    subject: 'Order Confirmation',
    message: 'Your order has been placed.',
    status: 'delivered',
    createdAt: '2024-01-15T10:30:00Z',
  };

  return {
    status: 200,
    body: { notification, requestId: ctx.requestId },
  };
});

export default {
  fetch: service.createFetchHandler(),
};


// ============================================
// worker-notification-service/wrangler.toml
// ============================================
/*
name = "worker-notification-service"
main = "src/index.js"
compatibility_date = "2024-01-01"

# Secrets:
# INTERNAL_SIGNING_SECRET

# Notification service may need to look up user details
[[services]]
binding = "USER_SERVICE"
service = "worker-user-service"
*/


// ============================================
// deploy.sh
// Deployment script for all workers
// ============================================
/*
#!/bin/bash
set -euo pipefail

echo "=== Deploying Edge Microservices Architecture ==="

# Set shared secrets across all workers
INTERNAL_SECRET=$(openssl rand -hex 32)
JWT_SECRET=$(openssl rand -hex 32)

echo "Setting secrets for internal workers..."

for WORKER in worker-notification-service worker-product-service worker-order-service worker-user-service edge-gateway; do
  echo "Setting INTERNAL_SIGNING_SECRET for $WORKER"
  echo "$INTERNAL_SECRET" | wrangler secret put INTERNAL_SIGNING_SECRET --name "$WORKER"
done

echo "Setting JWT_SECRET for gateway..."
echo "$JWT_SECRET" | wrangler secret put JWT_SECRET --name edge-gateway

# Deploy internal workers first (order matters for service bindings)
echo ""
echo "=== Deploying internal workers ==="

echo "Deploying notification service..."
cd worker-notification-service && wrangler deploy && cd ..

echo "Deploying product service..."
cd worker-product-service && wrangler deploy && cd ..

echo "Deploying user service..."
cd worker-user-service && wrangler deploy && cd ..

echo "Deploying order service..."
cd worker-order-service && wrangler deploy && cd ..

# Deploy gateway last
echo ""
echo "=== Deploying gateway ==="
cd worker-gateway && wrangler deploy && cd ..

echo ""
echo "=== Deployment complete ==="
echo "JWT_SECRET (save this securely): $JWT_SECRET"
echo "Gateway URL: https://edge-gateway.<your-subdomain>.workers.dev"
*/


// ============================================
// test/integration.js
// Integration test script
// ============================================

async function runTests(gatewayUrl, jwtSecret) {
  console.log('=== Running Integration Tests ===\n');

  // Helper to create JWT
  async function createJWT(payload) {
    const header = btoa(JSON.stringify({ alg: 'HS256', typ: 'JWT' }))
      .replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');

    const now = Math.floor(Date.now() / 1000);
    const fullPayload = { ...payload, iat: now, exp: now + 3600 };
    const payloadB64 = btoa(JSON.stringify(fullPayload))
      .replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');

    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(jwtSecret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['sign']
    );

    const signatureBuffer = await crypto.subtle.sign(
      'HMAC',
      key,
      encoder.encode(`${header}.${payloadB64}`)
    );

    const signature = btoa(String.fromCharCode(...new Uint8Array(signatureBuffer)))
      .replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');

    return `${header}.${payloadB64}.${signature}`;
  }

  const adminToken = await createJWT({ sub: '1', role: 'admin', name: 'Admin' });
  const userToken = await createJWT({ sub: '2', role: 'user', name: 'User' });

  let passed = 0;
  let failed = 0;

  async function test(name, fn) {
    try {
      await fn();
      console.log(`✅ ${name}`);
      passed++;
    } catch (err) {
      console.log(`❌ ${name}: ${err.message}`);
      failed++;
    }
  }

  function assert(condition, message) {
    if (!condition) throw new Error(message);
  }

  // Health check
  await test('Health check returns 200', async () => {
    const res = await fetch(`${gatewayUrl}/health`);
    assert(res.status === 200, `Expected 200, got ${res.status}`);
    const body = await res.json();
    assert(body.status === 'healthy', 'Expected healthy status');
  });

  // Unauthenticated request
  await test('Unauthenticated request returns 401', async () => {
    const res = await fetch(`${gatewayUrl}/api/users`);
    assert(res.status === 401, `Expected 401, got ${res.status}`);
  });

  // Security headers present
  await test('Security headers are present', async () => {
    const res = await fetch(`${gatewayUrl}/health`);
    assert(res.headers.get('X-Content-Type-Options') === 'nosniff', 'Missing X-Content-Type-Options');
    assert(res.headers.get('X-Frame-Options') === 'DENY', 'Missing X-Frame-Options');
    assert(res.headers.has('Strict-Transport-Security'), 'Missing HSTS');
    assert(res.headers.has('Content-Security-Policy'), 'Missing CSP');
  });

  // Get users as admin
  await test('Get users as admin', async () => {
    const res = await fetch(`${gatewayUrl}/api/users`, {
      headers: { 'Authorization': `Bearer ${adminToken}` },
    });
    assert(res.status === 200, `Expected 200, got ${res.status}`);
    const body = await res.json();
    assert(Array.isArray(body.users), 'Expected users array');
    assert(body.requestId, 'Expected requestId');
  });

  // Get products
  await test('Get products', async () => {
    const res = await fetch(`${gatewayUrl}/api/products`, {
      headers: { 'Authorization': `Bearer ${userToken}` },
    });
    assert(res.status === 200, `Expected 200, got ${res.status}`);
    const body = await res.json();
    assert(Array.isArray(body.products), 'Expected products array');
  });

  // Get single product
  await test('Get single product', async () => {
    const res = await fetch(`${gatewayUrl}/api/products/prod-001`, {
      headers: { 'Authorization': `Bearer ${userToken}` },
    });
    assert(res.status === 200, `Expected 200, got ${res.status}`);
    const body = await res.json();
    assert(body.product.id === 'prod-001', 'Expected product prod-001');
  });

  // Create order
  await test('Create order', async () => {
    const res = await fetch(`${gatewayUrl}/api/orders`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${userToken}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        items: [
          { productId: 'prod-001', quantity: 2 },
          { productId: 'prod-002', quantity: 1 },
        ],
      }),
    });
    assert(res.status === 201, `Expected 201, got ${res.status}`);
    const body = await res.json();
    assert(body.order.id, 'Expected order ID');
    assert(body.order.total > 0, 'Expected positive total');
  });

  // 404 for unknown route
  await test('Unknown route returns 404', async () => {
    const res = await fetch(`${gatewayUrl}/api/unknown`, {
      headers: { 'Authorization': `Bearer ${userToken}` },
    });
    assert(res.status === 404, `Expected 404, got ${res.status}`);
  });

  // Request ID tracking
  await test('Request ID is returned in response', async () => {
    const res = await fetch(`${gatewayUrl}/api/products`, {
      headers: { 'Authorization': `Bearer ${userToken}` },
    });
    assert(res.headers.has('X-Request-ID'), 'Expected X-Request-ID header');
    assert(res.headers.has('X-Response-Time'), 'Expected X-Response-Time header');
  });

  console.log(`\n=== Results: ${passed} passed, ${failed} failed ===`);
}

